# scripts/kb_change_review.py
# Run in CI to identify KB articles that may be affected by code changes
# Pass changed file paths as arguments; outputs list of articles to review

import sys, json
from pathlib import Path

# Map code areas to KB article tags
CODE_TO_KB_TAG = {
    "app/api/completions.py": ["kb-api-chat-completions", "kb-troubleshoot-completions"],
    "app/safety/filter.py":   ["kb-safety-policy", "kb-troubleshoot-safety-refusals"],
    "app/rate_limiter.py":    ["kb-api-rate-limits", "kb-troubleshoot-429"],
    "app/models/loader.py":   ["kb-troubleshoot-model-load", "kb-api-models"],
}

def find_affected_articles(changed_files: list[str]) -> set[str]:
    affected = set()
    for f in changed_files:
        for pattern, tags in CODE_TO_KB_TAG.items():
            if pattern in f or f.endswith(pattern):
                affected.update(tags)
    return affected

if __name__ == "__main__":
    changed = sys.argv[1:]
    affected = find_affected_articles(changed)
    if affected:
        print("KB articles that may need review due to code changes:")
        for tag in sorted(affected):
            print(f"  - {tag}")
        # In CI: create GitHub issues for each affected article
    else:
        print("No KB articles affected by these code changes.")

# scripts/kb_faq_review.py
# Analyzes support tickets to identify FAQ gaps and stale articles

from collections import Counter
import re

# These would be real API calls to your support system (Zendesk, Freshdesk, etc.)
def get_ticket_subjects_last_30_days() -> list[str]:
    return ["how do I set max_tokens", "why am I getting 429", "can I use streaming",
            "what is the context window", "how to use function calling",
            "rate limit keeps hitting", "streaming response format"]  # example

def get_kb_article_searches_last_30_days() -> Counter:
    # What users searched for in the KB — searches that returned no results
    # are the highest-value FAQ gaps
    return Counter({"streaming": 145, "rate limit": 230, "function calling": 89,
                    "pricing": 67, "token counting": 120})

def identify_faq_gaps(tickets: list[str], searches: Counter) -> list[str]:
    # Topics with > 5 tickets that don't have a KB article
    topic_counts = Counter()
    keywords = ["rate limit", "token", "streaming", "function calling", "pricing"]
    for ticket in tickets:
        for kw in keywords:
            if kw.lower() in ticket.lower():
                topic_counts[kw] += 1

    gaps = []
    for topic, count in topic_counts.items():
        if count >= 5 and searches.get(topic, 0) >= 50:
            gaps.append(f"{topic}: {count} tickets, {searches.get(topic, 0)} searches")
    return gaps

tickets = get_ticket_subjects_last_30_days()
searches = get_kb_article_searches_last_30_days()
gaps = identify_faq_gaps(tickets, searches)
if gaps:
    print("FAQ gap analysis — articles to create:")
    for g in gaps:
        print(f"  - {g}")
